// Alle Feed-Eintraege einsammeln und auf die neuesten 15 begrenzen
const entries = $input.all().slice(0, 15);
const now = new Date();
const dateStr = now.toLocaleDateString('de-DE', { timeZone: 'Europe/Berlin' });

const rows = entries.map(function (item) {
  const j = item.json;
  const title = j.title || 'Ohne Titel';
  const link = j.link || '#';
  let snippet = (j.contentSnippet || j.content || '').toString().trim();
  if (snippet.length > 220) snippet = snippet.slice(0, 220) + '\u2026';

  let dateLabel = '';
  const raw = j.isoDate || j.pubDate;
  if (raw) {
    const p = new Date(raw);
    if (!isNaN(p.getTime())) {
      dateLabel = p.toLocaleString('de-DE', { timeZone: 'Europe/Berlin', dateStyle: 'short', timeStyle: 'short' }) + ' Uhr';
    }
  }

  let li = '<li style="margin-bottom:16px;">';
  li += '<a href="' + link + '" style="font-weight:600;color:#0a58ca;text-decoration:none;">' + title + '</a>';
  if (dateLabel) li += '<div style="color:#777;font-size:12px;margin-top:2px;">' + dateLabel + '</div>';
  if (snippet) li += '<div style="color:#333;font-size:14px;margin-top:4px;">' + snippet + '</div>';
  li += '</li>';
  return li;
}).join('');

const html =
  '<div style="font-family:Arial,Helvetica,sans-serif;max-width:640px;margin:0 auto;color:#111;">' +
  '<h2 style="margin-bottom:4px;">Tagesschau \u2013 Top-Themen</h2>' +
  '<p style="color:#777;font-size:13px;margin-top:0;">' + dateStr + ' \u00b7 ' + entries.length + ' Meldungen</p>' +
  '<ul style="list-style:none;padding:0;">' + rows + '</ul>' +
  '<hr style="border:none;border-top:1px solid #eee;margin-top:24px;">' +
  '<p style="color:#999;font-size:12px;">Automatisch erstellt mit n8n \u00b7 Quelle: tagesschau.de</p>' +
  '</div>';

const subject = 'Tagesschau Top-Themen \u2013 ' + dateStr;

return [{ json: { html: html, subject: subject, count: entries.length } }];
